import { Injectable, inject } from '@angular/core';
import { SupabaseService } from './Base/supabase.service';
import { AuthService } from './Base/auth.service';

@Injectable({ providedIn: 'root' })
export class RestaurantFollowerService {
  private supabaseService = inject(SupabaseService);
  private authService = inject(AuthService);

  private get client() {
    return this.supabaseService.getSupabaseClient();
  }

  /** Controlla se l'utente corrente segue già il ristorante */
  async isFollowing(restaurantId: string): Promise<boolean> {
    const userId = this.authService.currentUserValue?.id;
    if (!userId) return false;

    const { data, error } = await this.client
      .from('restaurant_followers')
      .select('id')
      .eq('user_id', userId)
      .eq('restaurant_id', restaurantId)
      .maybeSingle();

    return !error && !!data;
  }

  /** Segui un ristorante */
  async follow(restaurantId: string): Promise<boolean> {
    const userId = this.authService.currentUserValue?.id;
    if (!userId) return false;

    const { error } = await this.client
      .from('restaurant_followers')
      .insert({ user_id: userId, restaurant_id: restaurantId });

    return !error;
  }

  /** Smetti di seguire */
  async unfollow(restaurantId: string): Promise<boolean> {
    const userId = this.authService.currentUserValue?.id;
    if (!userId) return false;

    const { error } = await this.client
      .from('restaurant_followers')
      .delete()
      .eq('user_id', userId)
      .eq('restaurant_id', restaurantId);

    return !error;
  }

  /** Toggle — ritorna il nuovo stato (true = ora segue) */
  async toggleFollow(restaurantId: string): Promise<boolean> {
    const following = await this.isFollowing(restaurantId);
    if (following) {
      await this.unfollow(restaurantId);
      return false;
    } else {
      await this.follow(restaurantId);
      return true;
    }
  }

  /** Tutti i ristoranti seguiti dall'utente corrente */
  async getFollowedRestaurants(): Promise<string[]> {
    const userId = this.authService.currentUserValue?.id;
    if (!userId) return [];

    const { data, error } = await this.client
      .from('restaurant_followers')
      .select('restaurant_id')
      .eq('user_id', userId);

    return error ? [] : (data || []).map(r => r.restaurant_id);
  }

  /** Numero di follower di un ristorante (pubblico, per mostrarlo nella UI) */
  async getFollowerCount(restaurantId: string): Promise<number> {
    const { count, error } = await this.client
      .from('restaurant_followers')
      .select('id', { count: 'exact', head: true })
      .eq('restaurant_id', restaurantId);

    return error ? 0 : (count ?? 0);
  }

async getFollowersForRestaurant(restaurantId: string): Promise<any[]> {
  // 1. Prendi i follower
  const { data: followers, error } = await this.client
    .from('restaurant_followers')
    .select('user_id, followed_at')          // ← followed_at, non created_at
    .eq('restaurant_id', restaurantId)
    .order('followed_at', { ascending: false }); // ← stessa correzione

  if (error) {
    console.error('❌ getFollowersForRestaurant error:', error);
    return [];
  }
  if (!followers?.length) return [];

  // 2. Prendi i profili utente
  const userIds = followers.map(f => f.user_id);
  const { data: users, error: usersError } = await this.client
    .from('users')
    .select('id, first_name, last_name, email')
    .in('id', userIds);

  if (usersError) {
    console.error('❌ users fetch error:', usersError);
  }

  // 3. Unisci manualmente
  return followers.map(f => ({
  user_id: f.user_id,
  followed_at: f.followed_at,  // ← solo questo, tolto l'alias created_at
  users: users?.find(u => u.id === f.user_id) || null
  }));
}

}